INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H6', 'אבד', 'heb', 'ʼâbad', 'aw-bad''', 'v', 'wander, lose, perish, destroy', 'אָבַד vb. perish (M I אבד, As. abâtu Dl W 184 Aram אֲבַד, Syriac).— Qal Pf. א׳ Nu 21:30 +; אָבְדוּ ψ 10:16 + (+ Ez 6:3 𝔊 Co) etc.; Impf. יֹאבַד Jb 3:3 Je 4:9; יֹאבֵ֑ד Jb 20:7 + 2t.; 3fs. תֹּאבַד Dt 22:3 + 4t.; תֹּאבֵ֑ד Jb 8:13 + 3t.; יֹאבְדוּ Ju 5:31 + 3t.; יֹאבֵ֑דוּ Jb 4:9 +; 3fpl. וַתֹּאבַדְנָה֙ I S 9:3; תֹּאבֵדוּן Dt 4:26 +; נֹאבֵ֑ד Jon 1:6, 3:9; נֹאבְדָה Jon 1:14 etc.; Inf. abs. אָבֹד Dt 4:26 + 2t.; cstr. אֲבֹד Dt 7:10 Pr 11:10; אֲבָדְךָ Dt 28:20; אָבְדֶ֑ךָ Dt 28:22; אֲבָדְכֶם Jos 23:13; אָבְדָם Ob 12 Pr 28:28; Pt. אֹבֵד Dt 26:5 + 7t.; cstr. אֹבַד Dt 32:28 (bef. ע? v. Di Bö § 378); etc. perish, die, of individuals (mostly late) Nu 17:27 (∥ גוע & (v. 28) מות), (also Dt 26:5? cf. infr.) Jon 1:6, 14 Jb 31:19 cf. 29:13 Pr 31:6 Est 4:14, 16, 16 Mi 4:9 Je 40:15 cf. Is 57:1 Pr 11:10 28:28 Ec 7:15 ψ 119:92; emphasis on morality Jb 4:20 ψ 146:4 Ec 9:6; Saul & Jonath., under fig. of weapons 2 S 1:27; lion Jb 4:11; caravan Jb 6:18 (cf. Di); cf. אָ׳ חָסִיד מִן־הָאָרֶץ Mi 7:2, וְאָ׳ מֶלֶךְ מֵֽעַזָּה Zc 9:5; perish, be exterminated (judgment for sin), of Israel Lv 26:38 Dt 8:19, 19, 20 28:20, 22 30:18, 18 Je 27:10, 15 cf. 6:21, Ob 12 cf. ψ 80:17 Is 27:13; other nations Dt 7:20 Je 10:15 51:18 ψ 2:12 10:16 83:18 cf. 9:4 Am 1:8 Is 41:11 60:12 cf. Jon 3:9 v. also Ex 10:7 Nu 21:29, 30 (JE) Je 48:46; house of Ahab 2 K 9:8; wicked in general Ju 5:31 Jb 4:9 cf. v 7, ψ 37:20 49:11 68:3 (∥ sim. of melting wax), 73:27 92:10; also Pr 19:9 21:28; לָנֶצַח א׳ Jb 20:7; cf. דֶרֶךְ רְשָׁעִים א׳ ψ 1:6; sq. מֵעַל הָאָ֑רֶץ (of annihilation of Isr.) Dt 4:26, 26 11:17 Jos 23:13, 16 (D); sq. מִתּוֹךְ הַקָּהָל (of Korah’s company) Nu 16:33 (JE); perish, be ruined, destroyed, of inanimate things, e.g. land Je 9:11 (∥ נִצְּתָה כַמִּדְבָּר) cf. 48:8; harvest Jo 1:11; Jonah’s gourd Jon 4:10; riches Je 48:36 Ec 5:13; vessel ψ 31:13; houses Am 3:15 (so oft. As. Dl W); city Ez 26:17 (but del. 𝔊 Co); cf. bamôth Ez 6:3 𝔊 Co; heavens & earth ψ 102:27. fig. perish, vanish, subj. memory Jb 18:17 ψ 9:7; name ψ', NULL);
