INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H413', 'אל', 'heb', 'ʼêl', 'ale', 'prep', 'near, with, among, to', 'אֶל (nearly always followed by Makkeph), prep. denoting motion to or direction towards (whether physical or mental).of motion to or unto a person or place Where the limit is actually entered, into Of direction towards anything Where the motion or direction implied appears from the context to be of a hostile character, אֶל = against Unto sometimes acquires from the context the sense of in addition to Metaph. in regard to, concerning, on account of Of rule or standard according to (rare) Expressing presence at a spot, against, at, by, not merely after verbs implying motion Prefixed to other preps. it combines with them the idea of motion or direction to base', NULL);
