INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H776', 'ארץ', 'heb', 'ʼerets', 'eh''-rets', 'n-f', 'earth, land', 'אֶ֫רֶץ n. f. & (seld.) m. earth, land earth, whole earth (opp. to a part) earth, opp. to heaven, sky earth = inhabitants of earth land = country, territory district, region trial territory piece of ground specif. land of Canaan, or Israel = inhabitants of land used even of Shᵉʼôl ground, surface of ground soil, as productive אֶרֶץ in phrases people of the land in measurements of distance the country of the plain, level or plain country land of the living end(s) of the earth pl. אֲרָצוֹת is almost wholly late; it denotes lands, countries, often in contrast to Canaan, lands of the nations, etc. base', NULL);
