INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1197', 'בער', 'heb', 'bâʻar', 'baw-ar''', 'v', 'kindle, consume, be (-come) brutish', '[בָּעַר] vb. burn, consume Qal burn Pi. kindle burn fig. consume, utterly remove Pu. burn (i.e. be supplied with fire), of fire-jar Hiph. kindle burn up base', 1);
