INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1234', 'בקע', 'heb', 'bâqaʻ', 'baw-kah''', 'v', 'cleave, rend, break, rip, open', 'בָּקַע vb. cleave, break open or through Qal cleave, cleave open break through or into Niph. be cleft, rent open be broken into Pi. cleave, cut to pieces, or rend open Pu. be ripped open Hiph. break into Hoph. the city was broken into Hithp. burst (themselves) open, of wine-skins; cleave asunder, of valleys base', NULL);
