INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1272', 'ברח', 'heb', 'bârach', 'baw-rakh''', 'v', 'bolt, flee', 'בָּרַח vb. go through, flee Qal go or pass through, of bar flee flee = hasten, come quickly Hiph. pass through cause to flee, put to flight base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1288', 'ברך', 'heb', 'bârak', 'baw-rak''', 'v', 'kneel, bless, curse', '[בָּרַךְ] 329 vb. kneel, bless Qal kneel down bless Niph. bless oneself Pi. bless God, adore with bended knees God blesses men bless men salute, greet, with an invocation of blessing bless, with the antithetical meaning curse from the greeting in departing, saying adieu to, taking leave of; but rather a blessing overdone and so really a curse as in vulgar English as well as in the Shemitic cognates Pu. pass. to be blessed, adored prospered by God have prosperity invoked, by Balaam in gratitude Hiph. and he made his camel kneel Hithp. bless oneself, congratulate oneself in his heart base', NULL);
