INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1310', 'בשל', 'heb', 'bâshal', 'baw-shal''', 'v', 'boil, be done, ripen', 'בָּשַׁל vb. boil, seethe (intr.), grow ripe Qal boil, cook (intr.); grow ripe Pi. boil (tr.) cook (general) Pu. be boiled, sodden Hiph. ripened, brought to ripeness base', NULL);
