INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1350', 'גאל', 'heb', 'gâʼal', 'gaw-al''', 'v', 'redeem, be the next of kin, buy back, marry', 'גָּאַל vb. redeem, act as kinsman Qal act as kinsman, do the part of next of kin redeem, by payment of value assessed redeem, with God as subj. implying personal relationship Niph refl. redeem oneself pass. be redeemed base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1351', 'גאל', 'heb', 'gâʼal', 'gaw-al''', 'v', 'soil, desecrate', '[גָּאַל] vb. defile, late Niph. be defiled Pi. pollute, desecrate Pu. and they were desecrated out of the priesthood Hiph. I have polluted, i.e. stained, all my raiment. Hithp. defile himself base', 2);
