INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1504', 'גזר', 'heb', 'gâzar', 'gaw-zar''', 'v', 'cut, destroy, divide, exclude, decide', 'גָּזַר vb. cut, divide Qal divide, cut in two divide the Red Sea cut down cut off (piece of meat to eat, but obj. not expr.) cut off, i.e. destroy, exterminate decree Niph. be cut off, separated, excluded be cut off = destroyed, exterminate be decreed base', NULL);
