INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1518', 'גיח', 'heb', 'gîyach', 'ghee''-akh', 'v', 'gush forth, issue', '[גִּיחַ, גּוּחַ] vb. burst forth intrans. burst forth trans. draw forth from womb thrust forth, bring forth, fig. of travail base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1523', 'גיל', 'heb', 'gîyl', 'gheel', 'v', 'spin, rejoice, cringing, fear', '[גִּיל] vb. rejoice (go around or about, be excited to levity) Qal rejoice tremble base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1540', 'גלה', 'heb', 'gâlâh', 'gaw-law''', 'v', 'denude, exile, reveal', 'גָּלָה 189 vb. uncover, remove Qal uncover the ear of one, i.e. reveal to him intr. remove, depart go into exile Niph. refl. uncover oneself (one’s nakedness) discover or shew oneself pass. be uncovered (one’s nakedness) be disclosed, discovered be removed Pi. uncover disclose, discover, lay bare make known, shew, reveal Pu. be uncovered Hiph. carry away into exile, take into exile Hoph. carried into exile Hithp. was uncovered (naked) that his heart may reveal itself base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1541', 'גלה', 'arc', 'gᵉlâh', 'ghel-aw''', 'v', 'bring over', '[גְּלָא, גְּלָה] vb. reveal Pe. reveal secrets Pᵉ‛îl revealed Haph. take into exile base', NULL);
