INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1556', 'גלל', 'heb', 'gâlal', 'gaw-lal''', 'v', 'roll', '[גָּלַל] vb. roll, roll away Qal roll a stone Niph. roll, roll up or along Pilp. and I will roll thee down from the rocks Pō‛al garment rolled (dabbed, rolled over and over) in blood. Hithpo. roll oneself over and over Hithpalp. cf. Hithpo. Hiph. roll away stone from upon mouth of well base', 2);
