INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1869', 'דרך', 'heb', 'dârak', 'daw-rak''', 'v', 'tread, walk, string', 'דָּרַךְ vb. tread, march Qal tread, march, march forth tread upon tread wine- (or oil-) press tread (i.e. bend) the bow Hiph. tread, tread down tread (bend) the bow causat. cause to tread or march, lead base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1875', 'דרש', 'heb', 'dârash', 'daw-rash''', 'v', 'tread, frequent, follow, seek, ask, worship', 'דָּרַשׁ 162 vb. resort to, seek Qal (tread a place,) resort to, frequent seek, consult, inquire of seek deity in prayer and worship seek, with idea of demanding, require inquire, investigate (a matter) ask for, require, demand seek with application, study, follow, practise seek with care, care for Niph. let oneself be inquired of, consulted, only of God be sought out be required, of blood base', NULL);
