INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1878', 'דשן', 'heb', 'dâshên', 'daw-shane''', 'v', 'be fat, fatten, anoint, satisfy, remove, ashes', 'דָּשֵׁן vb. be fat, grow fat Qal fig. of Isr.’s prosperity Pi. causat. make fat i.e. anoint, symbol of festivity and joy; of bodily effect of good news; find a burnt-offering fat = acceptable; elsewhere denom.;—take away, clear away the fat ashes (acc. of altar cleared) Pu. pass. of causat. Pi. be made fat, of dust saturated Hothp. of Yahweh’s sword:—it hath fattened itself base', NULL);
