INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1897', 'הגה', 'heb', 'hâgâh', 'daw-gaw''', 'v', 'murmur, ponder', 'הָגָה vb. moan, growl, utter, speak, muse (only poet.) Qal of inarticulate sounds growl, of lion growling over prey groan, moan, in distress (like dove) utter of inarticulate sounds (soliloquize) meditate, muse imagine, devise Po. a conceiving and an uttering, out of the heart, lying words Hiph. those that make chirpings and mutterings, of necromancers and wizards base', 1);
