INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1921', 'הדר', 'heb', 'hâdar', 'haw-dar''', 'v', 'swell, favor, honour, be high, proud', '[הָדַר] vb. swell (?), honour, adorn Qal swell honour, pay honour to adorn Niph. were (not) honoured Hithp. honour oneself, i.e. claim honour base', NULL);
