INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1931', 'הוא', 'heb', 'hûwʼ', 'hoo', 'p', 'he, she, it, self, same, this, that, as, are', 'הוּא m. הִיא f., pron. of the 3rd ps. sing. he, she, used also (in both genders) for the neuter it an emph. he (she, it, they), sometimes equivalent to himself (herself, itself, themselves), or (esp. with the art.) that (those) It resumes the subj. with emph. Where, however, the pron. follows the pred., its position gives it the minimum of emphasis, and it expresses (or resumes) the subject as unobtrusively as possible It anticipates (as it seems) the subject As an emph. predicate, of God In a neuter sense, that, it (of an action, occurrence, matte, etc.) With the art.: so regularly when joined to a subst. defined itself by the art. base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1932', 'הוא', 'arc', 'hûwʼ', 'hoo', 'p', '× are', 'הוּא 14 m. הִיא 7 f. pron. of 3s. he, she, it base', NULL);
