INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1961', 'היה', 'heb', 'hâyâh', 'haw-yaw', 'v', 'exist, be, become, come to pass', 'הָיָה 3570 vb. fall out, come to pass, become, be Qal Fall out, happen occur, take place, come about, come to pass esp. & very oft., come about, come to pass וַיְהִי and it came to pass that, most often (c. 292 t.) rarely also Pf. c. וְ conj. וְהָיָה less oft. וְהָיָה Pf. consec. and it shall come to pass, or frequentat. came to pass (repeatedly, etc.) Come into being, become abs., in lively narrative, arise, appear, come sq. prep. become sq. pred. noun (to be viewed as implicit accus.) sq. pred. adj. become like sq. pred. לְ pers. sq. לְ pred. oft. c. לְ pred. לְ pers. with עַל and לְ sts. c. לְ pers. only = became the property of, come into the possession of Be (often with subbordinate idea of becoming) exist, be in existence abide, remain, continue with word of locality, be in or at a place, be situated, stand, lie as copula, joining subj. & pred. periphrastic conjug. Niph. either be done, be brought about, or occur, come to pass be done, finished, gone base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H1963', 'היך', 'heb', 'hêyk', 'hake', 'adv', 'how?', 'הֵיךְ adv. how? base', NULL);
