INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2388', 'חזק', 'heb', 'châzaq', 'khaw-zak''', 'v', 'fasten, seize, be strong, courageous, strengthen, cure, help, repair, fortify, obstinate, bind, restrain, conquer', 'חָזַק 291 vb. be or grow firm, strong, strengthen Qal intrans. be or grow strong transit. only strengthened him not Pi. make strong (physically) strengthen the hands (acc.) of anyone, sustain, encourage make strong = bold, encourage make firm make rigid, hard, i.e. perverse, obstinate, harden Hiph. make strong, strengthen make firm, the kingdom display strength make severe, of battle support = repair prevail esp. take or keep hold of, seize, grasp Hithp. strengthen oneself put forth strength, use one''s strength withstand hold strongly with base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2398', 'חטא', 'heb', 'châṭâʼ', 'khaw-taw''', 'v', 'miss, sin, forfeit, lack, expiate, repent, lead astray, condemn', 'חָטָא 238 vb. miss (a goal or way), go wrong, sin Qal miss sin, miss the goal or path of right and duty incur guilt, penalty by sin, forfeit Pi. bear loss make a sin offering purify from sin purify from uncleanness Hiph. miss the mark induce or cause to sin bring into guilt, condemnation, punishment Hithp. miss oneself, lose oneself, fig. for be bewildered, beside oneself purify oneself from uncleanness base', NULL);
