INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2490', 'חלל', 'heb', 'châlal', 'khaw-lal''', 'v', 'bore, wound, dissolve, profane, break, begin, play', '[חָלַל] vb. pollute, defile, profane Niph. reflex. pollute, defile oneself Pass., be polluted, defiled Pi. defile, pollute violate the honour of, dishonour violate a covenant treat a vineyard as common Pu. my great name which is profaned among the nations Hiph. I will not let my holy name be profaned any more. he shall not violate his word begin Hoph. then it was begun (= men began) to call on the name of י׳ base', NULL);
