INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2664', 'חפש', 'heb', 'châphas', 'khaw-fas''', 'v', 'seek, conceal oneself, mask', '[חָפַשׂ] vb. search Qal search, search out search for = think out, devise search = test Niph. searched out = exposed and plundered Pi. search through search for Pu. be searched for = be hidden Hithp. disguise oneself (lit. let oneself be searched for) base', NULL);
