INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2673', 'חצה', 'heb', 'châtsâh', 'khaw-tsaw''', 'v', 'cut, split, halve', 'חָצָה vb. divide Qal divide shall not halve their days, i.e. enjoy even half of the normal number Niph. be divided base', NULL);
