INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2707', 'חקה', 'heb', 'châqâh', 'khaw-kaw''', 'v', 'carve, delineate, entrench', 'חָקָה vb. only Pu. cut in, carve Pu. carved figure on wall = subst. carved work Hithp. thou gavest thee a graving (= markest a line) for (i.e. about) the soles of my feet, fixed limits for them base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2710', 'חקק', 'heb', 'châqaq', 'khaw-kak''', 'v', 'hack, engrave, be a scribe, enact, cut, prescribe', '[חָקַק] vb. cut in, inscribe, decree Qal cut in cut in or on, upon, engrave, inscribe trace, mark out of a law, engrave, inscribe Po‛el inscribe (as a law), enact (poet.) prescriber of laws, hence (as sovereign authority in a warlike clan) commander commander’s staff Pu. that which is decreed Hoph. inscribed base', NULL);
