INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2717', 'חרב', 'heb', 'chârab', 'khaw-rab''', 'v', 'parch, desolate, destroy, kill', '[חָרֵב] be waste, desolate Qal be waste, desolate Niph. as adj., desolate city Hiph. lay waste, make desolate Hoph. she is laid waste base', 2);
