INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2790', 'חרש', 'heb', 'chârash', 'khaw-rash''', 'v', 'scratch, engrave, plough, fabricate, devise, be silent, let alone, be deaf', '[חָרֵשׁ] vb. 1. be silent, dumb, speechless; 2. be deaf; chiefly poet. Qal be silent, alw. of God’s keeping silence when men pray be deaf Hiph. be silent (= exhibit silence) once causat. make silent be deaf, shew deafness base', 2);
