INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2803', 'חשב', 'heb', 'châshab', 'khaw-shab''', 'v', 'plait, interpenetrate, weave, fabricate, plot, contrive, think, regard, value, compute', 'חָשַׁב vb. think, account Qal of man: think, account devise, plan, mean charge, impute esteem, value, regard invent ingenious and artistic things of God: think devise, plan, mean inpute, reckon esteem, value, regard invent ingenious and artistic things Niph. be accounted, thought, esteemed be computed, reckoned be imputed to any one Pi. think upon, consider, be mindful of think to do, devise, plan count, reckon, the years since a sale of land Hithp. among the nations it shall not reckon itself base', NULL);
