INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2814', 'חשה', 'heb', 'châshâh', 'khaw-shaw''', 'v', 'hush', '[חָשָׁה] vb. be silent, inactive, still (chiefly poet. and late) Qal be silent Hiph. exhibit silence, be silent shew inactivity causat. make still, quiet base', NULL);
