INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H2820', 'חשך', 'heb', 'châsak', 'khaw-sak''', 'v', 'restrain, refrain, refuse, spare, preserve, observe', 'חָשַׂךְ vb. withhold, refrain Qal withhold, keep back, keep for oneself keep one from evil, calamity hold in check refrain spare reserve for (abs.) restrain, check (pain) i.e. assuage Niph. at the day of calamity the wicked is spared base', NULL);
