INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3045', 'ידע', 'heb', 'yâdaʻ', 'yaw-dah''', 'v', 'know, seeing, observation, care, recognition, instruction, designation, punishment', 'יָדַע 943 vb. know Qal know, learn to know perceive perceive and see; find out and discern discriminate, distinguish know by experience recognize, admit, acknowledge, confess consider not know = not expect know a person, be acquainted with know a person carnally, of sexual intercourse know how, to do a thing, be able to do it be skilful in abs. have knowledge, be wise Niph. be made known, be or become known, of things make oneself known of pers. be perceived be instructed Pi. cause to know Pu. known Hiph. make known, declare Hoph. made known Hithp. make oneself known base', NULL);
