INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3117', 'יום', 'heb', 'yôwm', 'yome', 'n-m', 'day', 'יוֹם 2285 n.m. day day, opp. night Day as division of time יוֹם י׳ day of Yahweh, chiefly as time of his coming in judgment, involving often blessedness for righteous Pl. days of anyone Days יוֹם = time Phrases base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3161', 'יחד', 'heb', 'yâchad', 'yaw-khad''', 'v', 'be, one', '[יָחַד] vb. be united Qal in their assembly let my glory not be united Pi. unite my heart base', NULL);
