INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3190', 'יטב', 'heb', 'yâṭab', 'yaw-tab''', 'v', 'be, make well', '[יָטַב] vb. be good, well, glad, pleasing Qal be glad, joyful be well placed impers. be well for or with, go well with be pleasing Hithp. make glad, rejoice do good to, deal well with do well or thoroughly make a thing good, right, beautiful do well, right, ethically base', NULL);
