INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3198', 'יכח', 'heb', 'yâkach', 'yaw-kahh''', 'v', 'be right, argue, decide, justify, convict', '[יָכַח] vb. Hiph. decide, adjudge, prove Hiph. decide, judge adjudge, appoint shew to be right, prove convince, convict reprove, chide correct, rebuke Hoph. he is chastened also with pain Niph. come now and let us reason together; there an upright man might reason with him; and thou art set right, righted, justified Hithp. with Israel he will argue base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3201', 'יכל', 'heb', 'yâkôl', 'yaw-kole''', 'v', 'be able, can, could, may, might', 'יָכֹל, יָכוֹל 193 vb. be able, have power, prevail, endure Qal be able, to do a thing,, whether ability be physical, moral, constitutional, or dependent on external authority prevail abs. have ability, strength, only neg. base', NULL);
