INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3205', 'ילד', 'heb', 'yâlad', 'yaw-lad''', 'v', 'bear young, beget, act as midwife, show lineage', 'יָלַד 497 vb. bear, bring forth, beget Qal bear, bring forth less often beget of both parents Niph. be born Pi. cause (or help) to bring forth, viz., assist or tend as midwife Pu. be born Hiph. beget (a father a child) bear Hoph. day of one''s being born = birthday Hithp. declared their pedigree base', NULL);
