INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3235', 'ימר', 'heb', 'yâmar', 'yaw-mar''', 'v', 'exchange, change places', 'ימר vb. assumed in Thes to expl. Hiph. הֵימִיר = הֵמִיר Je 2:11, and Hithp. תִּתְיַמָּ֑רוּ Is 61:6; but on הימיר v. מור, and תִּתְיַמָּ֑רוּ is prob. from אמר q.v. supr. p. 56b. ref', NULL);
