INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3245', 'יסד', 'heb', 'yâçad', 'yaw-sad''', 'v', 'set, found, sit, settle, consult', 'יָסַד vb. establish, found, fix Qal found, establish Niph. fix or seat themselves close together, sit in conclave be founded Pi. found establish Pu. be founded, be laid, of a foundation Hoph. be founded base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3254', 'יסף', 'heb', 'yâçaph', 'yaw-saf''', 'v', 'add, augment, continue', 'יָסַף 214 vb. add Qal add Niph. join (intr.), join oneself to be joined, added to Hiph. add sq. inf. add to do = do again or more sq. Impf. sq. Impf. asynd. base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3255', 'יסף', 'arc', 'yᵉçaph', 'yes-af''', 'v', 'add.', '[יְסַף] vb. add;—Hoph. Dn 4:33 ref', NULL);
