INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3259', 'יעד', 'heb', 'yâʻad', 'yaw-ad''', 'v', 'fix, meet, summon, direct, engage', 'יָעַד vb. appoint Qal appoint, a time; place; a rod; assign or designate as concubine Niph. reflexive, meet at an appointed place meet by appointment gather, assemble by appointment Po‛ēl Pf. Hiph. Impf. who will make me meet him at the appointed place (of judgment) Hoph. Pt. be set, placed before base', NULL);
