INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3318', 'יצא', 'heb', 'yâtsâʼ', 'yaw-tsaw''', 'v', 'go, bring, out', 'יָצָא 1068 vb. go or come out Qal go or come out or forth from (מִן) a place go forth from (the presence of) a person in technical senses of flight, involving escape depart of inanimate things with especial emphasis on idea of origin, source of children as going forth from loins (of father) go forth to a place go forward, proceed to or toward something come or go forth, with esp. ref. to purpose or result of combinations Hiph. cause to go or come out, bring out, lead out fig. obj. persons, bring out of (מִן) distress, etc. bring out animals inanimate obj. fig. subj. י׳, bring forth from (מִן) Hoph. be brought forth base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3319', 'יצא', 'arc', 'yᵉtsâʼ', 'yets-aw''', 'v', 'finish.', 'שׁיציא Kt, שֵׁיצִי Qr vb. bring out (to an end), finish;—Ezr 6:15 ref', NULL);
