INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3332', 'יצק', 'heb', 'yâtsaq', 'yaw-tsak''', 'v', 'pour out, melt, cast as metal, place firmly, stiffen, grow hard', 'יָצַק vb. pour, cast, flow Qal pour, pour out cast (objects of metal) Pt.pass. as adj. fig. cast, hard, of crocodile’s scales intrans. flow, pour Hiph. pour (oil) Hoph. be poured Pt. = cast, molten Pt., fig. firmly established base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3335', 'יצר', 'heb', 'yâtsar', 'yaw-tsar''', 'v', 'mould, potter, determine', 'יָצַר vb. form, fashion Qal of human activity of divine activity Niph. before me a god was not formed (created) Pu. days (that) were pre-ordained (in divine purpose) Hoph. any weapon that is formed against thee will not prosper. base', NULL);
