INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3363', 'יקע', 'heb', 'yâqaʻ', 'yaw-kah''', 'v', 'sever, be dislocated, abandon, impale', 'יָקַע vb. be dislocated, alienated Qal dislocated (Jacob’s thigh); elsewhere torn away, alienated from any one Hiph. of some solemn form of execution, but mng. uncertain Hoph. pass. of Hiph. base', NULL);
