INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3372', 'ירא', 'heb', 'yârêʼ', 'yaw-ray''', 'v', 'fear, revere, frighten', 'יָרֵא vb. fear Qal fear, be afraid stand in awe of fear, reverence, honour Niph. be fearful, dreadful cause astonishment and awe inspire reverence, godly fear, and awe Piel. make afraid, terrify base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3381', 'ירד', 'heb', 'yârad', 'yaw-rad''', 'v', 'descend, go downwards, fall, bring down', 'יָרַד 380 vb. come or go down, descend Qal 306 come or go down go down (usu. from mountain or hill-country into plain), to battle go down to (acc.) threshing-floor go down (abs.) from Palestine to Egypt from Jerusalem from altar go down = sink, in water go down to She’ôl fig. going down (dissolving) in tears = be prostrated of divine manifestations: descend of inanimate things Hiph. cause to come or go down bring down send down rain = cause to flow down = lay prostrate to (acc.) threshing-floor bring down to She’ôl take down (from cart) let down Hoph. be brought down be taken down base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3384', 'ירה', 'heb', 'yârâh', 'yaw-raw''', 'v', 'flow, lay, throw, shoot, point, aiming, teach', '[יָרָא] vb. shoot, pour Qal shoot with arrows Hiph. and they shot at; Pt. pl. the shooters, archers Hoph. he that watereth shall himself also be watered base', NULL);
