INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3423', 'ירש', 'heb', 'yârash', 'yaw-rash''', 'v', 'occupy, driving, possessing, seize, rob, inherit, expel, impoverish, ruin', 'יָרַשׁ 229 vb. take possession of, inherit, dispossess Qal take possession of, esp. bu force, have as a possession, often with collat. idea of taking in place of others, succeeding to, inheriting inherit, sq. acc. pers. = be one''s heir = impoverish Niph. be (dispossessed =) impoverished, come to poverty Pi. the fruit of thy ground shall the cricket get full possession Hiph. cause to possess or inherit cause (others) to possess or inherit, then gen. dispossess = impoverish nearly = bring to ruin, destroy take possession of a land base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3427', 'ישב', 'heb', 'yâshab', 'yaw-shab''', 'v', 'sit, dwell, remain, settle, marry', 'יָשַׁב 1090 vb. sit, remain, dwell Qal sit sit, sit down sit down sit = be set (as a jewel) remain, stay, tarry with special emphasis of qualifying phr. dwell, have one’s abode of a land or city, sit, abide, seated in its place, fig. for be inhabited Niph. be inhabited, of land Pi. and they shall set their encampments in thee Hiph. cause to sit cause to abide cause to dwell cause cities to be inhabited marry (prop. give a dwelling to) Hoph. and ye be made to dwell alone in the midst of the land base', NULL);
