INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3456', 'ישם', 'heb', 'yâsham', 'yaw-sham''', 'v', 'lie waste', '[יָשַׁם] vb. be desolate base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3462', 'ישן', 'heb', 'yâshên', 'yaw-shane''', 'v', 'be slack, languid, sleep, die, grow old, stale, inveterate', '[יָשֵׁן] vb. sleep Qal sleep, go to sleep, and be sleep Niph. only in deriv. sense of become inactive or stationary Pi. causat. she made him sleep base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3467', 'ישע', 'heb', 'yâshaʻ', 'yaw-shah''', 'v', 'be open, wide, free, be safe, free, succor', '[יָשַׁע] vb. Hiph. deliver; Niph. intrans. and pass. Niph. be liberated, saved (prop. placed in freedom) be saved in battle, victorious Hiph. deliver, save (prop. give width and breadth to, liberate) save from moral troubles give victory to base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3474', 'ישר', 'heb', 'yâshar', 'yaw-shar''', 'v', 'be straight, even, be, make, right, pleasant, prosperous', 'יָשַׁר vb. be smooth, straight, right Qal go straight fig., be pleasing, agreeable, right in ethical sense, straightforward, upright Pi. make smooth, straight lead straight along, direct esteem right, approve Pu. gold made level, laid smoothly out, upon the graven work Hiph. let thine eyelids look straight before thee base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3487', 'ית', 'arc', 'yath', 'yath', 'prt', 'sign of the object of a verb', 'יָת mark of accus.;—Dn 3:12 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3488', 'יתב', 'arc', 'yᵉthib', 'yeth-eeb''', 'v', 'sit, dwell', 'יְתִב vb. sit, dwell Pe. sit, be seated dwell Haph. cause to dwell base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3498', 'יתר', 'heb', 'yâthar', 'yaw-thar''', 'v', 'jut, exceed, excel, remain, be left, leave, cause to abound, preserve', '[יָתַר] 107 vb. remain over Qal Pt. the remainder Niph. be left over, remain over Hiph. leave over, leave abs. leave a remnant save over, i.e. presevre alive excel, shew pre-eminence shew excess = have more than enough base', NULL);
