INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3512', 'כאה', 'heb', 'kâʼâh', 'kaw-aw''', 'v a', 'despond, deject', '[כָּאָה] vb. Niph. be disheartened, cowed Niph. then shall he be cowed; downhearted Hiph. Inf. cstr. base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3513', 'כבד', 'heb', 'kâbad', 'kaw-bad''', 'v', 'be heavy, burdensome, severe, dull, numerous, rich, honorable, make weighty', 'כָּבֵד vb. be heavy, weighty, burdensome, honoured Qal be heavy, in weight heavy, insensible, dull be honoured Niph. pass. be made heavy fr. abundance be honoured, enjoy honour, of man medial, get oneself glory (or honour), of God Pi. make heavy, insensible make honourable, honour, glorify, usu. c. human subj. Pu. be made honourable, honoured Hiph. make heavy make heavy, dull, unresponsive, the ears cause to be honoured Hithp. make oneself heavy, dense, numerous honour oneself base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3518', 'כבה', 'heb', 'kâbâh', 'kaw-baw''', 'v', 'expire, extinguish', '[כָּבָה] vb. be quenched, extinguished, go out, of fire or lamp Qal be quenched, extinguished Pi. quench, extinguish base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3526', 'כבס', 'heb', 'kâbaç', 'kaw-bas''', 'v', 'trample, wash, fulling', '[כָּבַס] 51 vb. (tread), wash Qal highway of fuller’s (= treader’s, washer’s) field Pi. wash garments (i.e. by treading) wash person Pu. be washed, of garment Hothp. after the plague is washed out base', NULL);
