INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3541', 'כה', 'heb', 'kôh', 'ko', 'prt', 'like this, thus, so, here, hither, now', 'כֹּה demonstr.adv. thus, here of manner, thus of place, here of time, hitherto base', NULL);
