INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3557', 'כול', 'heb', 'kûwl', 'kool', 'v', 'keep in, measure, maintain', '[כּוּל] vb. comprehend, contain Qal who hath comprehended the dust of the earth in a shalish-measure Pilp. sustain, maintain, contain Polp. were supplied with food Hiph. contain, hold, hold in, endure base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3559', 'כון', 'heb', 'kûwn', 'koon', 'v n-m', 'be erect, set up, establish, fix, prepare, apply, appoint, render sure, proper, prosperous', '[כּוּן] 218 vb. prob. be firm, only in der. conj. Niph. be set up, established, fixed in a moral sense, be directed aright, of ways prepare, be ready pass. be prepared, of judgments Hiph. establish, set up fix, so as to be ready, make ready, prepare, a gift provide for, provide, furnish direct one''s face toward arrange, order Hoph. be established, of throne be prepared for Po‛lēl. set up, establish constitute, make, a man (in womb) fix, so as to be ready direct Po‛lal. be established Hithpo‛l. be established base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3576', 'כזב', 'heb', 'kâzab', 'kaw-zab''', 'v', 'lie, deceive', '[כָּזַב] vb. lie, be a liar Qal Pt. Niph. his hope has been made deceptive Pi. lie, tell a lie disappoint, fail Hiph. who will make me a liar? i.e. prove me to be so base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3582', 'כחד', 'heb', 'kâchad', 'kaw-khad''', 'v', 'secrete, destroy', '[כָּחַד] vb. not in Qal; Pi. Hiph. hide, efface; Niph. (usu.) pass. Niph. be hidden be effaced, destroyed Pi. hide Hiph. hide efface, annihilate base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3583', 'כחל', 'heb', 'kâchal', 'kaw-khal''', 'v', 'paint', '[כָּחַל] vb. paint (eyes)—only in Ez 23:40 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3584', 'כחש', 'heb', 'kâchash', 'kaw-khash''', 'v', 'be untrue, lie, feign, disown, disappoint, fail, cringe', 'כָּחַשׁ vb. be disappointing, deceive, fail, grow lean Qal my flesh hath grown lean (away) fr. fatness Niph. thine enemies shall cringe Pi. deceive act deceptively against cringe = come cringing disappoint, fail Hithp. shall come cringing to me base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3588', 'כי', 'heb', 'kîy', 'kee', 'conj', 'relative conjunction', 'כִּי conj. that, for, when that Of time, when, of the past elsewhere כִּי has a force approximating to if, though it usu. represents a case as more likely to occur than אִם when or if, with a concessive force, i.e. though Because, since base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3607', 'כלא', 'heb', 'kâlâʼ', 'kaw-law''', 'v', 'restrict, hold back, in, prohibit', '[כָּלָא] vb. shut up, restrain, withhold (NH id.; Aram. כְּלָא, Syriac; Eth. Ethiopic restrain, hinder; As. kâlû, id.; Ar. Arabic protect Qor 21:43 cf. Ba ZMG 1887, 605 Anm. 4)— Qal Pf. 3 ms. sf. כְּלָאוֹ Je 32:3; 3 fs. כָּֽלְאָה Hg 1:10; 2 fs. sf. כְּלִתִ֫נִי I S 25:33; 1 s. כָּלִאתִי ψ 119:101; 3 pl. כָּֽלְאוּ Hg 1:10, כָּלוּ I S 6:10; Impf. 3 ms. יִכְלֶה Gn 23:6; 2 ms. תִכְלָא ψ 40:12; 2 fs. תִּכְלָ֑אִי Is 43:6; 1 s. אֶכְלָא ψ 40:10; Imv. sf. כְּלָאֵֽם Nu 11:28; Inf. cstr. לִכְלוֹא Ec 8:8; Pt. pass. כָלוּא Je 32:2, כָּלֻא ψ 88:9; (on the metapl. forms, as if fr. כלה, v. Ges § 76, 21 c Kö i. 611);— shut up, c. acc. I S 6:10 (+ בְ loc.), Je 32:3; pt. pass. Je 32:2 (בְ loc.), fig. ψ 88:9 (opp. יצא). restrain, c. acc. I S 25:33 (+ מִבּוֹא בְדָמִים), ψ 119:101 (+ מִכָּל־); כְּלָאֵם (sc. מֵהִתְנַבֵּא) Nu 11:28; כ׳ שְׂפָתַי ψ 40:10; כ׳ אֶת־הָרוּחַ Ec 8:8. On ψ 74:11 v. כלה Pi. 2. withhold, כ׳ אֶת־קִבְרוֹ מִמְּךָ מִקְּבֹר מֵתֶֽךָ Gn 23:6 (P), כ׳ רַחֲמֶיךָ מִמֶּנִּי ψ 40:12, Hg 1:10 b, prob. also v a (rd. מָ֑ל for MT 𝔊 מִטָּ֑ל, We); abs. אַל־תִּכְלָאִי (sc. exiles) Is 43:6 (∥ תְּנִי). Niph. Impf. וַיִּכָּלֵא הַגֶּשֶׁם מִן־הַשָּׁמָיִם Gn 8:2 (J), and the rain from heaven was restrained, cf. וַיִּכָּלְאוּ מַיִם רַבִּים Ez 31:15 (in fig.; ∥ מנע); וַיִּכָּלֵא הָעָם מֵהָבִיא Ex 36:6 (P). Pi. [Pf. כִּלָּא and] Inf. cstr. לְכַלֵּא v. כלה Pi. done', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3615', 'כלה', 'heb', 'kâlâh', 'kaw-law''', 'v', 'end, cease, be finished, perish, complete, prepare, consume', 'כָּלָה 204 vb. be complete, at an end, finished, accomplished, spent Qal be complete, at an end, of a period of time be completed, finished, of a work be accomplished, fulfilled be idealy complete, be determined, always in a bad sense, plotted be spent, used up (prop. come to an end), of water waste away, be exhausted, fail come to an end, vanish = perish, be destroyed Pi. complete, bring to an end, finish, a thing, task, work, etc. complete a period of time finish doing a thing make an end, end accomplish, fulfil, bring to pass accomplish in thought, determine put an end to, cause to cease cause to fail, exhaust, use up, spend destroy, sts. exterminate base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3634', 'כלל', 'heb', 'kâlal', 'kaw-lal''', 'v', 'complete', 'כָּלַל vb. complete, perfect base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3635', 'כלל', 'arc', 'kᵉlal', 'kel-al''', 'v', 'complete', '[כְּלַל] vb. complete Shaph. of building: he finished it Ishtaph. be completed, of walls base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3637', 'כלם', 'heb', 'kâlam', 'kaw-lawm''', 'v', 'wound, taunt, insult', '[כָּלַם] vb. only Niph. Hoph. be humiliated, Hiph. humiliate Niph. be humiliated, ashamed, put to shame, dishonoured, confounded Hiph. put to shame = insult, humiliate exhibit shame Hoph. we were not insulted, humiliated they were put to shame, dishonoured, confounded base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3642', 'כמה', 'heb', 'kâmahh', 'kaw-mah', 'v', 'pine after', 'כָּמַהּ vb. faint, only fig.—Qal ψ 63:2 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3647', 'כמס', 'heb', 'kâmaç', 'kaw-mas''', 'v', 'store away', '[כָּמַס] vb. store up, in Qal Dt 32:34 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3648', 'כמר', 'heb', 'kâmar', 'kaw-mar''', 'v', 'intertwine, contract, shrivel, be deeply affected with passion', '[כָּמַר] vb. Niph. grow warm and tender, be or grow hot base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3651', 'כן', 'heb', 'kên', 'kane', 'adv', 'set upright, just, rightly, so', 'כֵּן adv. so base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3655', 'כנה', 'heb', 'kânâh', 'kaw-naw''', 'v', 'address, eulogize', '[כָּנָה] vb. Pi. betitle, title, give an epithet or cognomen Pi. I have called thee by thy name, given thee a title Pu. he is betitled base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3664', 'כנס', 'heb', 'kânaç', 'kaw-nas''', 'v', 'collect, enfold', '[כָּנַס] vb. gather, collect Qal gather Pi. and I will gather you together Hithp. and the covering is (too) narrow when one gathers oneself together, i.e. the bed is too short to stretch oneself at full length, and when one (perforce) draws up the feet, the covering becomes too narrow. base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3665', 'כנע', 'heb', 'kânaʻ', 'kaw-nah''', 'v', 'bend, humiliate, vanquish', '[כָּנַע] vb. be humble, only in der. conj. Niph. reflex. humble oneself pass. be humbled, subdued Hiph. humble subdue enemies base', NULL);
