INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3782', 'כשל', 'heb', 'kâshal', 'kaw-shal''', 'v', 'totter, waver, falter, stumble, faint, fall', 'כָּשַׁל vb. stumble, stagger, totter Qal stumble at, over, something (lit. by means of) totter Niph. stumble be tottering, feeble Pi. only apparent Hiph. cause to stumble make feeble, weak Hoph. either and let them be ones who have stumbled before thee, i.e. regard them as such, or and let them be ones overthrown before thee base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3787', 'כשר', 'heb', 'kâshêr', 'kaw-share''', 'v', 'be acceptable, succeed, prosper', 'כָּשֵׁר vb. be advantageous, proper, suitable, succeed Qal and the thing be proper in the view of the king Hiph. an advantage for giving success in wisdom. base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3789', 'כתב', 'heb', 'kâthab', 'kaw-thab''', 'v', 'grave, write', 'כָּתַב 223 vb. write Qal write = write down, describe in writing = register, enroll = decree Niph. be written = be written down, recorded Pi. frequent. base', NULL);
