INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3807', 'כתת', 'heb', 'kâthath', 'kaw-thath''', 'v', 'bruise, strike', '[כָּתַת] vb. beat, crush by beating Qal beat or crush fine beat, hammer (ploughshares into swords) Pi. Pf.;—as Qal 1. beat or crush fine Pu. and they were beaten in pieces, one nation against another. Hiph. beat in pieces an enemy Hoph. and to ruins is the gate crushed base', NULL);
