INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H3920', 'לכד', 'heb', 'lâkad', 'law-kad''', 'v', 'catch, capture, choose, cohere', 'לָכַד 121 vb. capture, seize, take (by lot) Qal capture, seize fig. of entrapping men of taking by lot Niph. be captured in war of men, be caught be taken by lot Hithp. they grasp each other, and cannot be separated base', NULL);
