INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5060', 'נגע', 'heb', 'nâgaʻ', 'naw-gah''', 'v', 'touch, lay the hand upon, reach, arrive, acquire, strike', 'נָגַע 150 vb. touch, reach, strike Qal touch of י׳ touching earth, mountains, etc. nearly = strike, pass. stricken touch = harm reach, extend to Niph. be stricken, defeated (in battle), i.e. feign to be so Pi. strike (with leprosy, 2 acc.) Pu. be stricken by diseases Hiph. cause to touch; reach, approach, arrive base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5062', 'נגף', 'heb', 'nâgaph', 'naw-gaf''', 'v', 'push, gore, defeat, stub, inflict', 'נָגַף vb. strike, smite Qal strike, smite Niph. be smitten Hithp. = stumble base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5064', 'נגר', 'heb', 'nâgar', 'naw-gar''', 'v', 'flow, stretch out, pour out, down, deliver over', '[נָגַר] vb. pour, flow, run Niph. be poured, split pour oneself, flow, trickle, of eye (in tears) fig. vanish be stretched out (?) Hiph. pour down, hurl down Hoph. of mountains melting at theophany. base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5065', 'נגש', 'heb', 'nâgas', 'naw-gas''', 'v', 'drive, tax, harass, tyrannize', '[נָגַשׂ] vb. press, drive, oppress, exact Qal press, drive to work exact Pt. (= subst.) driver, taskmaster Niph. hard pressed by enemy; treated harshly of suffering servant of י׳; recipr. tyrannize over each other base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5066', 'נגש', 'heb', 'nâgash', 'naw-gash''', 'v', 'be, come, bring, near, lie with, attack, worship, present, adduce, stand back', '[נָגַשׁ] 125 vb. draw near, approach Qal draw near or come near Niph. draw near Hiph. cause to approach, bring near, bring Hoph. thy feet have not been brought near (put into) fetters; it (impers.) is offered to my name Hithp. draw near! base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5068', 'נדב', 'heb', 'nâdab', 'naw-dab''', 'v', 'to impel, to volunteer, to present spontaneously', 'נָדַב vb. incite, impel Qal whose heart incited Hithp. volunteer offer free-will-offerings base', NULL);
