INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5080', 'נדח', 'heb', 'nâdach', 'naw-dakh''', 'v', 'off', '[נָדַח] vb. impel, thrust, banish Qal trans. impel (i.e. wield) an axe thrust away, banish Niph. be impelled be thrust out, banished driven away (fr. herd, i.e.) straying thrust away, aside Pu. thrust into darkness Hiph. thrust, move, impel thrust out, banish thrust away, aside compel, force, subj. adulteress (by flattery) Hoph. chased, hunted base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5086', 'נדף', 'heb', 'nâdaph', 'naw-daf''', 'v', 'shove, disperse', '[נָדַף] vb. drive, drive asunder base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5087', 'נדר', 'heb', 'nâdar', 'naw-dar''', 'v', 'promise', 'נָדַר vb. vow base', NULL);
