INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5091', 'נהה', 'heb', 'nâhâh', 'naw-haw''', 'v', 'groan, bewail, assemble', 'נָהָה vb. wail, lament Qal lament Niph. went mourning after base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5094', 'נהיר', 'arc', 'nᵉhîyr', 'neh-heere''', 'n-m', 'illumination, wisdom', '', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5095', 'נהל', 'heb', 'nâhal', 'naw-hal''', 'v', 'sparkle, flow, conduct, protect, sustain', '[נָהַל] vb. Pi. lead, guide to a watering-place or station, and cuase to rest there; bring to a station or place of rest; lead, guide; refresh Pi. lead to a watering-place (or station), and cause to rest there lead or bring to a station, a goal lead, guide give rest to refresh with food Hithp. journey by stations, stages base', NULL);
