INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5106', 'נוא', 'heb', 'nûwʼ', 'noo', 'v', 'refuse, forbid, dissuade, neutralize', '[נוא] vb. hinder, restrain, frustrate Qal but read Hiph. Hiph. restrain, forbid (performance of vow); frustrate (device of people); refuse refrain, make averse the heart base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5107', 'נוב', 'heb', 'nûwb', 'noob', 'v', 'germinate, make, flourish, utter', '[נוּב] vb. bear fruit (poet.) Qal only fig., abs. of righteous under fig. of tree; if wealth beareth fruit; beareth the fruit of wisdom. Po‛l. fig. for makes to flourish. base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5110', 'נוד', 'heb', 'nûwd', 'nood', 'v', 'nod, waver, wander, flee, disappear, console, deplore, taunt', 'נוּד vb. move to and fro, wander, shudder, shew grief Qal move to and fro, wander aimlessly, as fugitive flutter waver, wave, shake shew grief (i.e. by shaking or nodding head) Hiph. cause to wander aimlessly, as fugitives make a wagging, wag with the head Hoph. and the worthless, like briers made to flutter (tossed away) are they Hithpo‛lel move oneself to and fro, sway, totter shake oneself, in excitement bemoan oneself base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5111', 'נוד', 'arc', 'nûwd', 'nood', 'v', 'flee', '[נוּד] vb. flee;—Pe. Dn 4:11. ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5115', 'נוה', 'heb', 'nâvâh', 'naw-vaw''', 'v', 'rest, beauty, celebrate', '[נָוָה] vb. only Hiph. (si vera l.) lit. beautify base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5117', 'נוח', 'heb', 'nûwach', 'noo''-akh', 'v', 'rest, settle, dwell, stay, let fall, place, let alone, withdraw, give comfort', 'נוּחַ vb. rest Qal rest, settle down and remain repose, be quiet, have rest Hiph. cause to rest = give rest to cause to rest (i.e. light) upon lay or set down, deposit, let lie let remain, leave (in present condition) leave = depart from abandon let alone (refrain from interfering with) permit Hoph. no rest is granted to us as subst. = space left, open space base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5120', 'נוט', 'heb', 'nûwṭ', 'noot', 'v', 'quake', '[נוּט] vb. dangle, shake;—Qal ψ 99:1 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5123', 'נום', 'heb', 'nûwm', 'noom', 'v', 'slumber', 'נוּם vb. be drowsy, slumber base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5125', 'נון', 'heb', 'nûwn', 'noon', 'v', 'resprout, propagate by shoots, be perpetual', '[נוּן, נִין] vb. propagate, increase;—Qal (or Hiph. ?) Impf. ינין Kt; > Niph. ינּוֹן Qr ψ 72:17 let his name have increase (or, if Niph., be propagated, spread); but dub. ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5127', 'נוס', 'heb', 'nûwç', 'noos', 'v', 'flit, vanish', '', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5128', 'נוע', 'heb', 'nûwaʻ', 'noo''-ah', 'v', 'waver', 'נוּעַ vb. quiver, wave, waver, tremble, totter Qal wave totter, go tottering Niph. be tossed about Hiph. toss about shake, cause to totter (shake), disturb cause to wander base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5130', 'נוף', 'heb', 'nûwph', 'noof', 'v', 'quiver, vibrate, rock', '[נוּף] vb. move to and fro, wave, besprinkle Qal I have besprinkled my couch with myrrh Po‛lel he brandisheth his hand toward the mt. Hiph. wield, move to and fro in using it Shake or wave the hand swing to and fro, as a signal Oft. term. techn. in P (H), of rite in which originally the priest lifted his share of offering and waved it, i.e. moved it toward altar and back, in token of its presentation to God and its return by him to priest Shed abroad Hoph. be waved base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5132', 'נוץ', 'heb', 'nûwts', 'noots', 'v', 'flash, fly', '[נָצָה] vb. fly (?);—only Qal Pf. 3 pl. La 4:15 (of homeless exiles); text very dub. ref', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5134', 'נוק', 'heb', 'nûwq', 'nook', 'v', 'suckle', '[נוּק] vb. whence might come, Hiph. suckle, nurse;—Ex 2:9 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5136', 'נוש', 'heb', 'nûwsh', 'noosh', 'v', 'be sick, distressed', '[נוּשׁ] vb. be sick;—Qal ψ 69:21 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5137', 'נזה', 'heb', 'nâzâh', 'naw-zaw''', 'v', 'spirt, besprinkle', '[נָזָה] vb. (dub.) spring, leap;—hence, acc. to many, Hiph. Is 52:15 ref', 2);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5140', 'נזל', 'heb', 'nâzal', 'naw-zal''', 'v', 'drip, shed', '[נָזַל] vb. flow, trickle, drop, distil (poet.) Qal flow distil Hiph. cause to flow base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5142', 'נזק', 'arc', 'nᵉzaq', 'nez-ak''', 'v', 'suffer, inflict, loss', '[נְזַק] vb. suffer injury Pe. Haph. injure base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5144', 'נזר', 'heb', 'nâzar', 'naw-zar''', 'v', 'hold aloof, abstain, apostatize, set apart, devote', '[נָזַר] vb. dedicate, consecrate, separate, in relig. and ceremonial sense Niph. devote, dedicate oneself unto Hiph. and ye shale keep the sons of Isr. sacredly separate from their uncleanness base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5148', 'נחה', 'heb', 'nâchâh', 'naw-khaw''', 'v', 'guide, transport', '[נָחָה] vb. lead, guide Qal lead, bring Hiph. lead, guide base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5162', 'נחם', 'heb', 'nâcham', 'naw-kham''', 'v', 'sigh, breathe, sorry, pity, console, rue, avenge', '[נחם] vb. Niph. be sorry, console oneself, etc. Niph. be sorry, moved to pity, have compassion, for others be sorry, rue, suffer grief, repent, of one’s own doings comfort oneself, be comforted comfort oneself, ease oneself, by taking vengeance Piel—comfort, console Pual; be comforted, consoled Hithpa.— be sorry, have compassion rue, repent of comfort oneself, be comforted ease oneself, by taking vengeance base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5169', 'נחץ', 'heb', 'nâchats', 'naw-khats''', 'v', 'be urgent', '[נָחַץ] vb. urge (?);—Qal 1 S 21:9 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5172', 'נחש', 'heb', 'nâchash', 'naw-khash''', 'v', 'hiss, whisper, prognosticate', '[נָחַשׁ] vb. only Pi. practice divination, divine, observe signs base', 2);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5181', 'נחת', 'heb', 'nâchath', 'naw-khath''', 'v', 'sink, descend, press, lead', '[נָחֵת] vb. (Aram. and poet.) go down, descend Qal go down, descend fig. descend in chastisement Niph. = penetrate Pi. cause to descend = press down Hiph. thither bring down thy heroes base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5182', 'נחת', 'arc', 'nᵉchath', 'nekh-ath''', 'v', 'descend, bring away, deposit, depose', '[נְחֵת] vb. descend Pe. Haph. (were) deposited. Hoph. be deposed base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5186', 'נטה', 'heb', 'nâṭâh', 'naw-taw''', 'v', 'stretch, bend', 'נָטָה 215 vb. stretch out, spread out, extend, incline, bend Qal stretch out, extend, hand, rod stretch line and plummet = offer Spread out, i.e. pitch, tent Bend, turn, incline Niph. be stretched out Hiph. rarely stretch out, hand rarely spread out cloth on rock usu. turn, incline base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5190', 'נטל', 'heb', 'nâṭal', 'naw-tal''', 'v', 'lift, impose', 'נָטַל vb. lift, bear Qal lift Pi. and he bare them base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5191', 'נטל', 'arc', 'nᵉṭal', 'net-al''', 'v', 'raise', '[נְטַל] vb. lift Pe. Pe‛îl be lifted base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5193', 'נטע', 'heb', 'nâṭaʻ', 'naw-tah''', 'v', 'strike, fix, plant', 'נָטַע vb. plant Qal plant plant, fig. = establish Niph. be planted, fig., = be established. base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5197', 'נטף', 'heb', 'nâṭaph', 'naw-taf''', 'v', 'ooze, distil gradually, fall in drops, speak by inspiration', '[נָטַף] vb. drop, drip Qal drop, drip Hiph. drip of speech, esp. prophecy base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5201', 'נטר', 'heb', 'nâṭar', 'naw-tar''', 'v', 'guard, cherish', '[נָטַר] vb. keep Qal keep, maintain keep, guard base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5202', 'נטר', 'arc', 'nᵉṭar', 'net-ar''', 'v', 'retain', '[נְטַר] vb. keep;—Pe. Dn 7:28. ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5203', 'נטש', 'heb', 'nâṭash', 'naw-tash''', 'v', 'pound, smite, disperse, thrust, reject, let alone, permit, remit', 'נָטַשׁ vb. leave, forsake, permit Qal leave, let alone usu. forsake, abandon permit Niph. be forsaken be loosened or loose (prop. be let alone, left to hang down) of ship’s tackle be let go, spread abroad Pu. palaces are abandoned, deserted base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5214', 'ניר', 'heb', 'nîyr', 'neer', 'v', 'till the soil', '[נִיר] vb. break up, freshly till base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5217', 'נכא', 'heb', 'nâkâʼ', 'naw-kaw''', 'v', 'smite, drive away', '[נָכָא] vb. smite, scourge;—only Niph. Jb 30:8 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5221', 'נכה', 'heb', 'nâkâh', 'naw-kaw''', 'v', 'strike', '[נָכָה] 501 vb. smite (not in Qal) Niph. and he shall be smitten [struck by weapon in battle] and die Pu. both be smitten down by the hail Hiph. lit., smite (with a single, non-fatal, blow), strike smite repeatedly, beat a man and they clapped hands (in applause) give a thrust (with fork) into pot; strike roots rarely smite (in battle) so as (merely) to wound smite, of sun Smite fatally Smite = attack, attack and destroy a company Of God smite with a plague, disease, etc. smite = chastise, or send judgment upon of God’s destroying palaces Hoph. be smitten base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5230', 'נכל', 'heb', 'nâkal', 'naw-kal''', 'v', 'defraud, act treacherously', '[נָכַל] vb. be crafty, deceitful, knavish Qal Pt. knave Pi. their wiles with which they beguiled you Hithp. they knavishly planned against him; to deal knavishly with base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5234', 'נכר', 'heb', 'nâkar', 'naw-kar''', 'v', 'scrutinize, recognition, acknowledge, be acquainted with, care for, respect, revere, disregard, ignore, be strange, reject, resign, dissimulate', '[נָכַר] vb. (not Qal) regard, recognize Niph. they are not recognized Pi. he regardeth not the opulent above the poor Hiph. regard, observe, esp. with a view to recognition Recognize (as formerly known) Be willing to recognize, acknowledge Be acquianted with Distinguish, understand Hithp. Impf by his deeds a youth maketh himself known, whether his doing be pure, etc. base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5239', 'נלה', 'heb', 'nâlâh', 'naw-law''', 'v', 'complete', 'נלה doubtful √:—for supposed Hiph. Is 33:1 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5243', 'נמל', 'heb', 'nâmal', 'naw-mal''', 'v', 'become clipped, circumcised', '[מָלַל] vb. circumcise Qal Jos 5:2. Niph. Gn 17:11 Hithpo. be cut off: ψ 58:8. ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5253', 'נסג', 'heb', 'nâçag', 'naw-sag''', 'v', 'retreat', '', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5254', 'נסה', 'heb', 'nâçâh', 'naw-saw''', 'v', 'test, attempt', '[נָסָה] vb. Pi. test, try test, try attempt, assay, try to do a thing test, try, prove, tempt [but not in the modern sense of the word] base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5255', 'נסח', 'heb', 'nâçach', 'naw-sakh''', 'v', 'tear away', '[נָסַח] vb. pull or tear away Qal the house of proud men will י׳ tear down Niph. and ye shall be torn away from off the land. base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5256', 'נסח', 'arc', 'nᵉçach', 'nes-akh''', 'v', 'pull down.', '[נְסַח] vb. pull away;—Hithpe. be pulled away: Ezr 6:11 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5258', 'נסך', 'heb', 'nâçak', 'naw-sak''', 'v', 'pour, cast, anoint', 'נָסַךְ vb. pour out Qal pour out pour out libations cast metal images Piel pour out as libation Hiph. pour out libations Hoph. be poured out base', 1);
