INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5264', 'נסס', 'heb', 'nâçaç', 'naw-sas''', 'v', 'raise a beacon', 'נסס (√ of foll. = be high or conspicuous? Hithpo‛l. Inf. לְהִתְנוֹסֵס ψ 60:6, acc. to some denom. from נֵס that it may be displayed, AV, cf. De; < v. נוס; Pt. מִתְנוֹסְסוֹת Zc 9:16 raised? prominent? (עַל־אַדְמָתוֹ; of precious stones, in fig.) very dub.; We Now del.; Gr מִתְנוֹצְצוֹת). done', 2);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5265', 'נסע', 'heb', 'nâçaʻ', 'naw-sah''', 'v', 'pull, start', 'נָסַע 147 vb. pull out or up, set out, journey Qal 137 pull out or up hence (from pulling up tent-pegs), set out depart journey, march (by stages) of wind Niph. be pulled up, removed Hiph. cause to set out, lead out remove base', 1);
