INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5276', 'נעם', 'heb', 'nâʻêm', 'naw-ame''', 'v', 'be agreeable', '[נָעֵם] vb. be pleasant, delightful, lovely;—Qal Pf. 3 fs. נָעֵ֑מָה Gn 49:15 (poem in J; of land); 2 ms. (of delightful friend) נָעַ֥מְתָּ לִי מְאֹד 2 S 1:26, also (of physical beauty) מִמִּי נָעָ֑מְתָּ Ez 32:19; 2 fs. (id.) וּמַה־נָּעַמְתְּ Ct 7:7 how lovely art thou!; 3 pl., of pleasant words, נָעֵ֑מוּ ψ 141:6; Impf. 3ms יִנְעָ֑ם: Pr 2:10 (of knowledge); 9:17; 24:25 is impers. c. ל, to them ... shall be delight. ref', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5286', 'נער', 'heb', 'nâʻar', 'naw-ar''', 'v', 'growl', '[נָעַר] vb. growl;—only Qal Je 51:38 ref', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5287', 'נער', 'heb', 'nâʻar', 'naw-ar''', 'v', 'tumble', '[נָעַר] vb. shake, shake out or off Qal shake out Niph. I am shaken out like a locust Pi. so may God shake utterly out every man from his house Hithp. shake thyself (free) base', 2);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5301', 'נפח', 'heb', 'nâphach', 'naw-fakh''', 'v', 'puff, inflate, blow hard, scatter, kindle, expire, disesteem', '[נָפַח] vb. breathe, blow Qal breathe, blow Pu. a fire not blown Hiph. (or if) the life of its (the land’s) owners I have caused them to breathe out base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5307', 'נפל', 'heb', 'nâphal', 'naw-fal''', 'v', 'fall', 'נָפַל 433 vb. fall, lie Qal 366 fall, by accident Esp. of violent death fig. = go to ruin, perish, etc. fig. = experience calamity fall, of a city Fall prostrate fall = prostrate oneself before fall upon one''s neck, in embrace Fall upon = attack desert or fall away to, go over to Fig., of deep sleep Other idiomatic uses = lie; = lie prostrate Hiph. cause to fall Of causing death; = overthrow, bring to destruction Esp. of casting lot Fig., let drop, cause to fail cause deep sleep to fall Other idioms Hithp. throw, or prostrate oneself base', NULL);
