INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5312', 'נפק', 'arc', 'nᵉphaq', 'nef-ak''', 'v', 'issue, bring out', 'נְפַק vb. go, or come, out, forth Pe. he went out Haph. bring forth base', NULL);
