INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5324', 'נצב', 'heb', 'nâtsab', 'naw-tsab''', 'v', 'station', '[נָצַב] vb. Niph. take one''s stand, stand Niph. station oneself, take one''s stand, for definite purpose stand = be stationed (by appointment, or in fulfillment of duty) take an upright position, stand be stationed = appointed over Pt. as subst. deputy = prefect (as appointed, deputed) stand firm Hiph. station, set set up, erect pillar cause to stand erect, waters fix, establish boundary Hoph. fixed, determined base', NULL);
