INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5337', 'נצל', 'heb', 'nâtsal', 'naw-tsal''', 'v', 'snatch', '[נָצַל] 212 vb. not in Qal; Pi. strip, plunder; Niph. deliver oneself, be delivered Hiph. snatch away, deliver Niph. reflex. tear oneself away, deliver oneself passive, be torn out or away Pi. strip off, spoil deliver Hiph. take away, snatch away rescue, recover deliver from deliver from sin and guilt Hoph. as a brand plucked out of the burning Hithp. and they stripped themselves of their ornaments. base', NULL);
