INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5367', 'נקש', 'heb', 'nâqash', 'naw-kash''', 'v', 'entrap', '[נָקַשׁ] vb. knock, strike, only in specif. sense of hit, strike or bring down (a bird), and only fig. Qal he striketh down the wicked Niph. lest thou be thrust (impelled) after them Pi. let the creditor strike at, take aim at Hithp. why art thou striking at my life? base', NULL);
