INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5422', 'נתץ', 'heb', 'nâthats', 'naw-thats''', 'v', 'tear', 'נָתַץ vb. pull down, break down Qal lit. pull down a structure fig. Niph. be pulled, broken, down Pi. tear down (chiefly late) Pu. be torn down Hoph. be broken down, broken base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5423', 'נתק', 'heb', 'nâthaq', 'naw-thak''', 'v', 'tear', '[נָתַק] vb. pull, draw, tear away, apart, off Qal draw away draw or pull off pull, tear away Niph. be drawn away be torn apart, or in two, snapped be separated Pi. tear apart, snap tear out, up Hiph. draw away drag them away Hoph. they were drawn away from the city base', NULL);
