INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5433', 'סבא', 'heb', 'çâbâʼ', 'saw-baw''', 'v', 'quaff, become tipsy', '[סָבָא] vb. imbibe, drink largely base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5437', 'סבב', 'heb', 'çâbab', 'saw-bab''', 'v', 'revolve, surround, border', 'סָבַב vb. turn about, go around, surround Qal turn, intrans. march, or walk, around go partly round, circle, skirt make a round, or circuit, go about to surround, encompass Niph. turn oneself against, close round upon turn round (from a direct course) esp. of boundary: turn round from, toward pass. be turned over to, into the power of Pi. to change, transform, the aspect of the matter Po‛. encompass (with protection) come about, assemble round march or go about enclose, envelop Hiph. turn (trans.), cause to turn bring over (i.e. to allegiance) turn into, of changing name = bring round, of changing name cause to go around surround with (acc.) wall perh. also encompass (as foe) Hoph. be turned, of cart wheel surrounded, i.e. set, of jewels base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5440', 'סבך', 'heb', 'çâbak', 'saw-bak''', 'v', 'entwine', '[סָבַךְ] vb. interweave Qal interwoven (entangled) thorns Pu. are interwoven base', NULL);
