INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5462', 'סגר', 'heb', 'çâgar', 'saw-gar''', 'v', 'shut, surrender', 'סָגַר vb. shut, close Qal shut door close in upon close up breach Pt. pass., closed up = closely joined with tight seal elsewhwere only Pt. pass. (gold shut up, and so prized, rare, fine?) Niph. subj. pers. be shut up be shut, closed, of city gates Pi. deliver up to (leave no other opening for one, shut one up to) Pu. of cities of prisoners of doors Hiph. deliver up to shut up base', 1);
