INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5557', 'סלף', 'heb', 'çâlaph', 'saw-laf''', 'v', 'wrench, subvert', 'סָלַף vb. twist, pervert, overturn Pi. pervert subvert, turn upside down, ruin base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5564', 'סמך', 'heb', 'çâmak', 'saw-mak''', 'v', 'prop, lean upon, take hold of', 'סָמַךְ 48 vb. lean, lay, rest, support Qal 41 lean or lay hand upon intrans. thy wrath hath rested upon me support, uphold, sustain Niph. reflex. support, or brace oneself Pi. sustain (refresh, revive) me with raisin-cakes. base', NULL);
