INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5584', 'סעה', 'heb', 'çâʻâh', 'saw-aw''', 'v', 'rush', '[סָעָה] vb. (dub.) rush, of storm-wind;—Qal ψ 55:9 ref', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5590', 'סער', 'heb', 'çâʻar', 'saw-ar''', 'v', 'rush upon, toss', '[סָעַר] vb. storm, rage Qal they [my foes] storm along to scatter me Niph. and the heart of the king … was enraged Pi. and storm them away (hurl them by a storm-wind) upon the nations. Po. shall be like chaff (which) is storm-driven from a threshing-floor. base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5594', 'ספד', 'heb', 'çâphad', 'saw-fad''', 'v', 'lament, wail', '[סָפַד] vb. wail, lament Qal wail, lament Niph. they shall not be bewailed base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5595', 'ספה', 'heb', 'çâphâh', 'saw-faw''', 'v', 'scrape, together, away', '[סָפָה] vb. sweep or snatch away, catch up Qal intrans. be snatched away trans. sweep away Niph. be swept away, destroyed be caught up, captured Hiph. I will catch up against them calamities base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5596', 'ספח', 'heb', 'çâphach', 'saw-fakh''', 'v', 'scrape, removal, association', '[סָפַח] vb. join, attach to Qal attach me, pray, to one of the priest’s offices. Niph. and they shall attach themselves to the house of Jacob Pi. joining (to it?) thy fury Pu. are joined together, hold themselves together Hithp. they have driven me out from joining myself with the inheritance of י׳. base', 1);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5603', 'ספן', 'heb', 'çâphan', 'saw-fan''', 'v', 'hide by covering, roof, wainscot, reserve', '', NULL);
