INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5609', 'ספר', 'arc', 'çᵉphar', 'sef-ar''', 'n-m', 'book', 'סְפַר n.m. book base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5612', 'ספר', 'heb', 'çêpher', 'say''-fer', 'n-m', 'writing, book', 'סֵ֫פֶר 185 n.m. missive, document, writing, book missive legal document book or scroll, in which something is written to preserve it for future use base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5619', 'סקל', 'heb', 'çâqal', 'saw-kal''', 'v', 'be weighty, lapidation, de', '[סָקַל] vb. stone, be put to death by stoning, also (Pi.) free from stones Qal pelt with stones, stone to death Niph. be stoned to death Pi. stone, pelt with stones free vineyard (acc.) from stones Pu. be stoned to death base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5628', 'סרח', 'heb', 'çârach', 'saw-rakh''', 'v', 'extend, excess', '[סָרַח] vb. go free, be unrestrained, overrun, exceed Qal go free, be unrestrained of overhanging stuffs (prop. overrunning, exceeding, extended beyond limits) Niph. usu. is their wisdom let loose (i.e. dismissed, gone)?; but is corrupt base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5637', 'סרר', 'heb', 'çârar', 'saw-rar''', 'v', 'turn, be refractory', 'סָרַר vb. be stubborn, rebellious base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H5640', 'סתם', 'heb', 'çâtham', 'saw-tham''', 'v', 'stop, repair, keep secret', 'סָתַם vb. stop up, shut up, keep close Qal stop up springs of water shut up, keep close Niph. the breaches [in the walls] had begun to be stopped up. Pi. of stopping wells quite up base', NULL);
