INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H7725', 'שוב', 'heb', 'shûwb', 'shoob', 'v', 'turn, return, retreat, again', 'שׁוּב 1056 vb. turn back, return Qal 683;—turn back, return: turn back return, come or go back esp. return unto of dying of revival from death fig. of human relations: return to leader, king = change so as to appoach (in purpose, desire) turn, i.e. resort to return to a physical condition abs. = change course of action fig., specif. of spiritual relations: turn back from God = apostatize of י׳, turn away turn back to God (= seek penitently) abs. repent turn back from evil of י׳ of י׳, return (to shew favour) of inanimate things (sts. personified, or treated as things of life): denoting repetition, etc. trans. Pō‛l. bring back fig. restore, refresh restore, repair lead away (enticingly) shew turning = apostatize Hiph. 353 cause to return, bring back bring back into bondage put back = draw back = give back, restore = relinguish = give in payment, requital bring one back (from dead) bring back heart = refresh bring back words of people bring back (in retribution) upon pay as recompense turn back, backward = repel, defeat turn away face late, turn toward, acc. face turn against bring back to mind, take into consideration = shew a turning away from your idols (i.e. turn away) reverse, revoke = repel, defeat Hoph. my money has been returned base', NULL);
INSERT OR IGNORE INTO roots (root_strongs, root_hebrew, root_lang, root_sbl, root_pron, root_pos, root_gloss, root_bdb, root_homonym) VALUES ('H7737', 'שוה', 'heb', 'shâvâh', 'shaw-vaw''', 'v', 'level, equalize, resemble, adjust', 'שָׁוָה vb. (be even, smooth, v. Pi., hence) agree with, be like, resemble Qal it was not equalled to me, i.e. not requited Pi. he hath levelled Hiph. make like Nithp. (appar.) are alike base', 1);
